import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import { authService } from "../services";
import "../styles/Auth.css";

const Login = () => {
  const [formData, setFormData] = useState({
    email: "",
    password: "",
  });
  const [loginType, setLoginType] = useState(""); // "" = choice, "admin" = admin, "user" = user
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!formData.email || !formData.password) {
      setError("Email and password are required");
      return;
    }

    if (!loginType) {
      setError("Please select Admin or User login");
      return;
    }

    setLoading(true);
    try {
      if (loginType === "admin") {
        // Use admin login endpoint
        await authService.adminLogin(formData);
      } else {
        // Use user login endpoint
        await authService.userLogin(formData);
      }
      navigate("/dashboard");
    } catch (err) {
      setError(err.response?.data?.message || "Login failed");
    } finally {
      setLoading(false);
    }
  };

  // Show role selection
  if (!loginType) {
    return (
      <div className="auth-container">
        <div className="auth-box login-choice">
          <h2>Select Login Type</h2>
          <p className="choice-subtitle">Choose your role to continue</p>

          <div className="choice-buttons">
            <button
              onClick={() => setLoginType("admin")}
              className="choice-btn admin-btn"
            >
              <div className="choice-icon">👨‍💼</div>
              <h3>Admin Login</h3>
              <p>Manage loads and users</p>
            </button>

            <button
              onClick={() => setLoginType("user")}
              className="choice-btn user-btn"
            >
              <div className="choice-icon">👤</div>
              <h3>User Login</h3>
              <p>Create and track loads</p>
            </button>
          </div>

          <p className="auth-link">
            Don't have an account? <Link to="/register">Register here</Link>
          </p>
        </div>
      </div>
    );
  }

  // Show login form
  return (
    <div className="auth-container">
      <div
        className={`auth-box ${loginType === "admin" ? "admin-login-box" : "user-login-box"}`}
      >
        <h2>{loginType === "admin" ? "Admin Login" : "User Login"}</h2>
        <p className="login-subtitle">
          {loginType === "admin" ? "Administrator Access" : "User Access"}
        </p>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Email</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              placeholder="Enter your email"
            />
          </div>
          <div className="form-group">
            <label>Password</label>
            <input
              type="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              placeholder="Enter password"
            />
          </div>
          <button
            type="submit"
            disabled={loading}
            className={`btn-primary ${loginType === "admin" ? "btn-admin" : "btn-user"}`}
          >
            {loading
              ? "Logging in..."
              : `Login as ${loginType === "admin" ? "Admin" : "User"}`}
          </button>
        </form>
        <p className="auth-link">
          <button
            onClick={() => setLoginType("")}
            style={{
              background: "none",
              border: "none",
              color: "#4caf50",
              cursor: "pointer",
              textDecoration: "none",
              fontWeight: "500",
            }}
          >
            ← Back to role selection
          </button>
        </p>
        <p className="auth-link">
          Don't have an account? <Link to="/register">Register here</Link>
        </p>
      </div>
    </div>
  );
};

export default Login;
